void add_token(mc_lex_token** p_tokens_tail, short class, short id, char* string, unsigned int pos, unsigned short len)
{
    mc_lex_token* token = (mc_lex_token*)malloc(sizeof(mc_lex_token));
    token->tid = id;
    token->tpos = pos;
    token->tlen = len;
    token->tstring = strndup(string, len);
    token->next = NULL;

    if ((*p_tokens_tail) == NULL){
        g_token_head = token;
        *p_tokens_tail = token;
    }else{
        (*p_tokens_tail)->next = (uint8_t*) token;
        *p_tokens_tail = token;
    }

    mc_sem_token_add(class, token);
}

// Register a lexer error at the given position without producing a parser token.
// The error is stored via mc_error_token_add() so mcc can collect it after parsing.
void add_token_error(mc_lex_token** p_tokens_tail, unsigned int pos, unsigned short len, const char* msg)
{
    (void)p_tokens_tail;
    mc_lex_token* token = (mc_lex_token*)malloc(sizeof(mc_lex_token));
    token->tid = 0;
    token->tpos = pos;
    token->tlen = len;
    token->tstring = strdup(msg);
    token->next = NULL;
    mc_error_token_add(token);
}

void free_tokens(mc_lex_token* tokens)
{
    mc_lex_token* ptok;
    while(tokens){
        ptok = tokens;
        tokens = (mc_lex_token*) tokens->next;
        free(ptok->tstring);
        free(ptok);
    }
}

void print_tokens(mc_lex_token* tokens)
{
    mprintf(MCC_LOG_TOKEN, "\n------------------------------------------------------------\n[print tokens]\n");
    mc_lex_token* ptok = tokens;
    while(ptok){
        mprintf(MCC_LOG_TOKEN, "[%d|%s|%d..%d] ", ptok->tid, ptok->tstring, ptok->tpos, ptok->tpos+ptok->tlen);
        ptok = (mc_lex_token*) ptok->next;
    }
}

